import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import { getStorage, ref, uploadBytes, getDownloadURL } from "firebase/storage";
import { initializeApp } from "firebase/app";

// 🔥 Cấu hình Firebase (thay bằng config của bạn)
const firebaseConfig = {
  apiKey: "AIzaSy....",
  authDomain: "your-app.firebaseapp.com",
  projectId: "your-app",
  storageBucket: "your-app.appspot.com",
  messagingSenderId: "123456789",
  appId: "1:123456789:web:xxxxxx"
};
initializeApp(firebaseConfig);
const storage = getStorage();

export default function NewFeed() {
  const navigate = useNavigate();
  const [toast, setToast] = useState(null);
  const [inputText, setInputText] = useState("");
  const [selectedFile, setSelectedFile] = useState(null);
  const [loading, setLoading] = useState(false);

  const [posts, setPosts] = useState([
    {
      name: "Ngọc Anh",
      text: "Buổi chiều đẹp quá!",
      images: [
        "https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/nwti4bgy_expires_30_days.png",
      ],
    },
    {
      name: "Minh Khang",
      text: "Hôm nay đi học vui ghê 😄",
      images: [],
    },
  ]);

  const [comments, setComments] = useState(posts.map(() => ({ input: "", list: [] })));

  const showToast = (message) => {
    setToast(message);
    setTimeout(() => setToast(null), 2500);
  };

  const handleUpload = async (file) => {
    const fileRef = ref(storage, `posts/${file.name}`);
    await uploadBytes(fileRef, file);
    return await getDownloadURL(fileRef);
  };

  const handlePost = async () => {
    if (!inputText.trim() && !selectedFile) {
      showToast("Vui lòng nhập nội dung hoặc chọn ảnh 📸");
      return;
    }

    setLoading(true);
    let imageUrl = "";
    if (selectedFile) {
      imageUrl = await handleUpload(selectedFile);
    }

    const newPost = {
      name: "Bạn",
      text: inputText,
      images: imageUrl ? [imageUrl] : [],
    };

    setPosts([newPost, ...posts]);
    setComments([{ input: "", list: [] }, ...comments]);
    setInputText("");
    setSelectedFile(null);
    showToast("Đăng bài thành công 🎉");
    setLoading(false);
  };

  return (
    <div className="flex min-h-screen bg-gray-100">
      {/* Nội dung chính */}
      <div className="flex-1 ml-[72px] flex flex-col">
        {/* Header cố định */}
        <div className="fixed top-0 left-0 right-0 flex items-center justify-between bg-[#88BCF8] py-3 px-6 z-50">
          <div className="flex items-center cursor-pointer" onClick={() => navigate("/")}>
            <img
              src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/iitooitd_expires_30_days.png"
              className="w-[120px] h-[110px] object-fill"
            />
          </div>

          {/* Thanh tìm kiếm */}
          <div className="flex items-center gap-2 max-w-[600px] w-full mx-6">
            <input
              placeholder="Tìm kiếm bạn bè hoặc bài viết..."
              className="text-black bg-[#F6FEFF] text-base flex-1 py-2 px-5 rounded-[50px] border-0 outline-none"
            />
            <img
              src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/qfk5vizv_expires_30_days.png"
              alt="search-icon"
              className="w-[45px] h-[45px] cursor-pointer hover:scale-110 transition-transform duration-200"
              onClick={() => navigate("/friends")}
            />
          </div>

          <div className="flex items-center gap-5">
            <img
              src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/nuk8gi0s_expires_30_days.png"
              className="w-[45px] h-[45px] cursor-pointer hover:scale-110 transition-transform"
            />
            <img
              src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/ceqzh6wh_expires_30_days.png"
              className="w-[45px] h-[45px] cursor-pointer hover:scale-110 transition-transform"
            />
          </div>
        </div>

        {/* Nội dung Feed */}
        <div className="flex flex-col items-center gap-4 mt-[130px] w-full">
          {/* Toast */}
          {toast && (
            <div className="fixed top-[140px] right-10 bg-black text-white px-6 py-3 rounded-lg shadow-lg z-50 animate-slide-down">
              {toast}
            </div>
          )}

          {/* Ô đăng bài */}
          <div className="bg-white w-full max-w-[1000px] rounded-lg shadow-md p-4 flex flex-col gap-3">
            <textarea
              placeholder="Bạn đang nghĩ gì?"
              value={inputText}
              onChange={(e) => setInputText(e.target.value)}
              className="w-full h-24 border rounded-lg p-3 text-black outline-none"
            ></textarea>

            <div className="flex items-center justify-between">
              <input
                type="file"
                accept="image/*"
                onChange={(e) => setSelectedFile(e.target.files[0])}
                className="text-black"
              />
              <button
                onClick={handlePost}
                disabled={loading}
                className="bg-blue-500 text-white px-4 py-2 rounded-lg hover:bg-blue-600 transition"
              >
                {loading ? "Đang đăng..." : "Đăng bài"}
              </button>
            </div>
          </div>

          {/* Danh sách bài post */}
          {posts.map((post, i) => (
            <div key={i} className="flex flex-col bg-[#A2D3FF] w-full max-w-[1000px] p-4 rounded-[10px] gap-4">
              {/* Header bài post */}
              <div className="flex items-center gap-4">
                <img
                  src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/oadiyd0v_expires_30_days.png"
                  className="w-[58px] h-[51px]"
                />
                <div className="flex flex-col">
                  <span className="text-black text-xl">{post.name}</span>
                  <span className="text-black text-base">Công khai</span>
                </div>
              </div>

              {/* Nội dung */}
              {post.text && <p className="text-black text-lg">{post.text}</p>}

              {/* Hình ảnh */}
              {post.images?.length > 0 ? (
                <div className="flex gap-4">
                  {post.images.map((img, idx) => (
                    <img
                      key={idx}
                      src={img}
                      className="w-1/2 h-64 object-cover rounded-lg shadow-md"
                      alt={`post-${idx}`}
                    />
                  ))}
                </div>
              ) : (
                <div className="flex justify-center items-center w-full h-64 bg-gray-200 rounded-lg border-2 border-dashed border-gray-400 text-gray-600">
                  <span>Chưa có ảnh</span>
                </div>
              )}

              {/* Bình luận */}
              <div className="flex items-center gap-2 mt-2">
                <img
                  src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/gyfive3m_expires_30_days.png"
                  className="w-[39px] h-[45px] cursor-pointer hover:scale-110 transition-transform"
                  onClick={() => showToast("Bạn đã thả tim ❤️")}
                />
                <input
                  placeholder="Bình luận..."
                  value={comments[i]?.input || ""}
                  onChange={(e) => {
                    const newComments = [...comments];
                    newComments[i].input = e.target.value;
                    setComments(newComments);
                  }}
                  className="flex-1 py-2 px-4 rounded-lg text-black border-0"
                />
                <button
                  className="bg-blue-500 text-white px-3 py-1 rounded-lg"
                  onClick={() => {
                    if (!comments[i]?.input?.trim()) return;
                    const newComments = [...comments];
                    newComments[i].list.push(newComments[i].input);
                    newComments[i].input = "";
                    setComments(newComments);
                  }}
                >
                  Gửi
                </button>
              </div>

              {/* Danh sách bình luận */}
              {comments[i]?.list?.length > 0 && (
                <div className="mt-2 ml-12 flex flex-col gap-1">
                  {comments[i].list.map((cmt, idx) => (
                    <span key={idx} className="text-black text-sm bg-white px-2 py-1 rounded-lg">
                      {cmt}
                    </span>
                  ))}
                </div>
              )}
            </div>
          ))}
        </div>
      </div>

      {/* Animation cho toast */}
      <style>
        {`
          @keyframes slideDown {
            0% { opacity: 0; transform: translateY(-20px); }
            100% { opacity: 1; transform: translateY(0); }
          }
          .animate-slide-down {
            animation: slideDown 0.3s ease-out;
          }
        `}
      </style>
    </div>
